import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { UserService } from '../../core/services/user.service';
import { AuthService } from '../../core/services/auth.service';
import { User } from '../../core/models/user.model';

@Component({
  selector: 'app-admin',
  templateUrl: './admin.component.html',
  styleUrls: ['./admin.component.scss'],
})
export class AdminComponent implements OnInit {
  users: User[] = [];
  isLoading = true;
  showForm = false;
  editingUser: User | null = null;
  successMessage = '';
  errorMessage = '';
  deleteConfirm: string | null = null;

  userForm!: FormGroup;
  currentUser!: User;

  constructor(
    private userService: UserService,
    private auth: AuthService,
    private fb: FormBuilder,
  ) {}

  ngOnInit(): void {
    this.currentUser = this.auth.currentUser!;
    this.initForm();
    this.loadUsers();
  }

  initForm(user?: User): void {
    this.userForm = this.fb.group({
      userId: [user?.userId ?? '', [Validators.required, Validators.minLength(3)]],
      name: [user?.name ?? '', [Validators.required, Validators.minLength(2)]],
      email: [user?.email ?? '', [Validators.required, Validators.email]],
      role: [user?.role ?? 'general', [Validators.required]],
      department: [user?.department ?? '', [Validators.required]],
      status: [user?.status ?? 'active', [Validators.required]],
      password: [
        '',
        user ? [] : [Validators.required, Validators.minLength(6)],
      ],
    });
    if (user) {
      this.userForm.get('userId')?.disable();
    }
  }

  loadUsers(): void {
    this.isLoading = true;
    this.userService.getUsers().subscribe({
      next: (users) => {
        this.users = users;
        this.isLoading = false;
      },
      error: () => {
        this.errorMessage = 'Failed to load users.';
        this.isLoading = false;
      },
    });
  }

  openAddForm(): void {
    this.editingUser = null;
    this.initForm();
    this.showForm = true;
    this.successMessage = '';
    this.errorMessage = '';
  }

  openEditForm(user: User): void {
    this.editingUser = user;
    this.initForm(user);
    this.showForm = true;
    this.successMessage = '';
    this.errorMessage = '';
  }

  cancelForm(): void {
    this.showForm = false;
    this.editingUser = null;
  }

  isInvalid(field: string): boolean {
    const c = this.userForm.get(field);
    return !!(c?.invalid && c.touched);
  }

  submitForm(): void {
    this.userForm.markAllAsTouched();
    if (this.userForm.invalid) return;

    const raw = this.userForm.getRawValue() as Partial<User> & { password?: string };

    if (this.editingUser) {
      const payload: Partial<User> & { password?: string } = {
        name: raw.name,
        email: raw.email,
        role: raw.role,
        department: raw.department,
        status: raw.status,
      };
      if (raw.password) payload.password = raw.password;

      this.userService.updateUser(this.editingUser.id, payload).subscribe({
        next: () => {
          this.successMessage = `User "${raw.name}" updated successfully.`;
          this.showForm = false;
          this.loadUsers();
        },
        error: (err: { error?: { message?: string } }) => {
          this.errorMessage = err.error?.message ?? 'Failed to update user.';
        },
      });
    } else {
      this.userService.createUser(raw as Partial<User> & { password: string }).subscribe({
        next: () => {
          this.successMessage = `User "${raw.name}" created successfully.`;
          this.showForm = false;
          this.loadUsers();
        },
        error: (err: { error?: { message?: string } }) => {
          this.errorMessage = err.error?.message ?? 'Failed to create user.';
        },
      });
    }
  }

  confirmDelete(userId: string): void {
    this.deleteConfirm = userId;
  }

  cancelDelete(): void {
    this.deleteConfirm = null;
  }

  deleteUser(user: User): void {
    this.userService.deleteUser(user.id).subscribe({
      next: () => {
        this.successMessage = `User "${user.name}" deleted.`;
        this.deleteConfirm = null;
        this.loadUsers();
      },
      error: (err: { error?: { message?: string } }) => {
        this.errorMessage = err.error?.message ?? 'Failed to delete user.';
        this.deleteConfirm = null;
      },
    });
  }

  getRoleBadge(role: string): string {
    return role === 'admin' ? 'badge--accent' : 'badge--primary';
  }

  getStatusBadge(status: string): string {
    return status === 'active' ? 'badge--success' : 'badge--muted';
  }

  isSelf(user: User): boolean {
    return user.id === this.currentUser.id;
  }

  getInitials(name: string): string {
    return name
      .split(' ')
      .filter((n) => n.length > 0)
      .map((n) => n[0] ?? '')
      .join('')
      .toUpperCase()
      .slice(0, 2);
  }

  get currentUserInitials(): string {
    return this.getInitials(this.currentUser.name);
  }
}
<div class="admin-layout">
  <!-- Sidebar (same as dashboard) -->
  <aside class="sidebar animate-fade-left">
    <div class="sidebar-top">
      <div class="sidebar-brand">
        <div class="brand-icon">
          <svg width="22" height="22" viewBox="0 0 36 36" fill="none">
            <path d="M10 18L18 10L26 18L18 26L10 18Z" stroke="white" stroke-width="2.2" stroke-linejoin="round"/>
            <circle cx="18" cy="18" r="3" fill="white"/>
          </svg>
        </div>
        <span class="brand-label">NexusPortal</span>
      </div>
      <nav class="sidebar-nav">
        <a routerLink="/dashboard" routerLinkActive="nav-item--active" class="nav-item">
          <svg class="nav-icon" width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.8" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zm10 0a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zm10 0a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z"/>
          </svg>
          Dashboard
        </a>
        <a routerLink="/admin" routerLinkActive="nav-item--active" class="nav-item nav-item--admin">
          <svg class="nav-icon" width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.8" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0z"/>
          </svg>
          User Management
          <span class="nav-badge">Admin</span>
        </a>
      </nav>
    </div>
    <div class="sidebar-footer">
      <div class="user-pill">
        <div class="avatar">{{ currentUserInitials }}</div>
        <div class="user-details">
          <span class="user-name">{{ currentUser.name }}</span>
          <span class="user-role admin">admin</span>
        </div>
      </div>
    </div>
  </aside>

  <!-- Main -->
  <main class="main-content">
    <header class="page-header">
      <div>
        <h1>User Management</h1>
        <p class="header-sub">Manage portal users and access control</p>
      </div>
      <button class="btn btn--primary" (click)="openAddForm()">
        <svg width="15" height="15" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 4v16m8-8H4"/>
        </svg>
        Add User
      </button>
    </header>

    <!-- Alerts -->
    <div *ngIf="successMessage" class="alert alert--success animate-fade">
      <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7"/></svg>
      {{ successMessage }}
    </div>
    <div *ngIf="errorMessage && !showForm" class="alert alert--error animate-fade">
      <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/></svg>
      {{ errorMessage }}
    </div>

    <!-- Add / Edit Form -->
    <div *ngIf="showForm" class="card form-card animate-fade">
      <div class="form-card-header">
        <h2>{{ editingUser ? 'Edit User' : 'Create New User' }}</h2>
        <button class="btn btn--ghost btn--sm" (click)="cancelForm()">✕ Cancel</button>
      </div>

      <form [formGroup]="userForm" (ngSubmit)="submitForm()" class="user-form">
        <div class="form-row">
          <div class="form-group">
            <label class="form-label">User ID</label>
            <input type="text" formControlName="userId" class="form-control" placeholder="e.g. jane.smith" />
            <div *ngIf="isInvalid('userId')" class="form-error">User ID required (min 3 chars).</div>
          </div>
          <div class="form-group">
            <label class="form-label">Full Name</label>
            <input type="text" formControlName="name" class="form-control" placeholder="Jane Smith" />
            <div *ngIf="isInvalid('name')" class="form-error">Full name required.</div>
          </div>
        </div>

        <div class="form-row">
          <div class="form-group">
            <label class="form-label">Email</label>
            <input type="email" formControlName="email" class="form-control" placeholder="jane@company.com" />
            <div *ngIf="isInvalid('email')" class="form-error">Valid email required.</div>
          </div>
          <div class="form-group">
            <label class="form-label">Department</label>
            <input type="text" formControlName="department" class="form-control" placeholder="Engineering" />
            <div *ngIf="isInvalid('department')" class="form-error">Department required.</div>
          </div>
        </div>

        <div class="form-row">
          <div class="form-group">
            <label class="form-label">Role</label>
            <select formControlName="role" class="form-control form-select">
              <option value="general">General User</option>
              <option value="admin">Admin</option>
            </select>
          </div>
          <div class="form-group">
            <label class="form-label">Status</label>
            <select formControlName="status" class="form-control form-select">
              <option value="active">Active</option>
              <option value="inactive">Inactive</option>
            </select>
          </div>
        </div>

        <div class="form-group">
          <label class="form-label">Password {{ editingUser ? '(leave blank to keep current)' : '' }}</label>
          <input type="password" formControlName="password" class="form-control" placeholder="Min 6 characters" autocomplete="new-password" />
          <div *ngIf="isInvalid('password')" class="form-error">Password required (min 6 chars).</div>
        </div>

        <div *ngIf="errorMessage && showForm" class="alert alert--error">{{ errorMessage }}</div>

        <div class="form-actions">
          <button type="button" class="btn btn--secondary" (click)="cancelForm()">Cancel</button>
          <button type="submit" class="btn btn--primary">
            {{ editingUser ? 'Save Changes' : 'Create User' }}
          </button>
        </div>
      </form>
    </div>

    <!-- Users Table -->
    <div class="card table-card animate-fade">
      <div class="table-header">
        <h2 class="table-title">All Users <span class="user-count">{{ users.length }}</span></h2>
      </div>

      <div *ngIf="isLoading" class="skeleton-rows">
        <div class="skeleton-row" *ngFor="let i of [1,2,3,4,5,6]">
          <div class="skeleton" style="width:40px; height:40px; border-radius:50%;"></div>
          <div style="display:flex; flex-direction:column; gap:6px; flex:1;">
            <div class="skeleton" style="width:150px; height:12px;"></div>
            <div class="skeleton" style="width:200px; height:11px;"></div>
          </div>
          <div class="skeleton" style="width:70px; height:22px; border-radius:12px;"></div>
          <div class="skeleton" style="width:70px; height:22px; border-radius:12px;"></div>
        </div>
      </div>

      <div class="table-wrapper" *ngIf="!isLoading">
        <table class="data-table">
          <thead>
            <tr>
              <th>User</th>
              <th>User ID</th>
              <th>Department</th>
              <th>Role</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let u of users" class="animate-fade">
              <td>
                <div class="user-cell">
                  <div class="user-avatar">{{ getInitials(u.name) }}</div>
                  <div>
                    <div class="cell--primary">{{ u.name }}</div>
                    <div class="cell--sub">{{ u.email }}</div>
                  </div>
                </div>
              </td>
              <td class="cell--mono">{{ u.userId }}</td>
              <td>{{ u.department }}</td>
              <td><span class="badge" [ngClass]="getRoleBadge(u.role)">{{ u.role }}</span></td>
              <td><span class="badge" [ngClass]="getStatusBadge(u.status)">{{ u.status }}</span></td>
              <td>
                <div *ngIf="deleteConfirm !== u.id" class="action-row">
                  <button class="btn btn--ghost btn--sm" (click)="openEditForm(u)">Edit</button>
                  <button
                    class="btn btn--danger btn--sm"
                    (click)="confirmDelete(u.id)"
                    [disabled]="isSelf(u)"
                    [title]="isSelf(u) ? 'Cannot delete yourself' : ''"
                  >Delete</button>
                </div>
                <div *ngIf="deleteConfirm === u.id" class="confirm-row">
                  <span class="confirm-text">Are you sure?</span>
                  <button class="btn btn--danger btn--sm" (click)="deleteUser(u)">Yes, Delete</button>
                  <button class="btn btn--ghost btn--sm" (click)="cancelDelete()">Cancel</button>
                </div>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  </main>
</div>
